function n(){const t=new Date().getHours();return t<12?"Good morning":t<17?"Good afternoon":"Good evening"}function r(t){return t>=1e6?(t/1e6).toFixed(1)+"M":t>=1e3?(t/1e3).toFixed(1)+"K":t.toString()}function o(t){return new Date(t).toLocaleDateString("en-US",{month:"short",day:"numeric",year:"numeric"})}function i(t){return new Date(t).toLocaleDateString("en-US",{month:"short",day:"numeric",hour:"numeric",minute:"2-digit"})}function a(t,e=80){return t?t.length>e?t.slice(0,e)+"...":t:""}export{o as a,i as b,r as f,n as g,a as t};
